resource myVm 'Microsoft.Compute/virtualMachines@2023-03-01' = {
  name: 'MyVM'
  location: resourceGroup().location
  identity: {
    type: 'SystemAssigned'   // enables system-assigned identity
  }
  properties: {
    // ... other VM properties
  }
}

// After deployment, reference the principal ID for role assignments
output principalId string = myVm.identity.principalId

using Azure.Identity;
using Azure.Security.KeyVault.Secrets;

var credential = new DefaultAzureCredential();
var client = new SecretClient(
    new Uri("https://mykeyvault.vault.azure.net"),
    credential);

KeyVaultSecret secret = await client.GetSecretAsync("my-database-password");
Console.WriteLine($"Secret: {secret.Value}");

resource "azurerm_linux_virtual_machine" "app_vm" {
  name                = "app-vm"
  resource_group_name = azurerm_resource_group.rg.name
  location            = azurerm_resource_group.rg.location
  size                = "Standard_B2s"
  admin_username      = "azureuser"

  identity {
    type = "SystemAssigned"
  }

  # ... other required properties (os_disk, network_interface_ids, etc.)
}

# Grant Key Vault Secrets User on the Key Vault
resource "azurerm_role_assignment" "vm_kv_access" {
  scope                = azurerm_key_vault.kv.id
  role_definition_name = "Key Vault Secrets User"
  principal_id         = azurerm_linux_virtual_machine.app_vm.identity[0].principal_id
}

-- Run this in the target Azure SQL database (as an Entra admin)
-- Replace 'MyVM' with the exact name of your Azure resource (VM/App Service/Function)
CREATE USER [MyVM] FROM EXTERNAL PROVIDER;
ALTER ROLE db_datareader ADD MEMBER [MyVM];
-- or for read+write:
-- ALTER ROLE db_datawriter ADD MEMBER [MyVM];
